SELECT id, code, name, domain_code, resource_code, action_code, risk_level, status, description
  FROM iam_permission
 WHERE deleted = false

   AND domain_code = #{domainCode}

 ORDER BY code
 LIMIT #{limit} OFFSET #{offset}

SELECT id FROM iam_permission WHERE deleted = false AND status = 'ENABLED' AND id IN
#{permissionId}
ORDER BY id
